module top_module(
    obf_DIODE,
    VPWR ,
    VGND ,
    VPB  ,
    VNB,
    VOUT
);input obf_DIODE;
    input signed [4:0] VPWR ;
    input signed [4:0] VGND ;
    input signed [4:0] VPB  ;
    input signed [4:0] VNB  ;
    output signed [4:0] VOUT;

    assign VOUT = (obf_DIODE == 1) ? (VPB - VNB) : 0;

endmodule
